  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires analyzing a large set of rules to determine if a specific causal chain exists. I will split this into rule extraction, chain tracing, and logical verification.",
  "helpers": [
    {
      "label": "rule_extractor",
      "instructions": "Identify and list all rules from the provided text that involve the butterfly, the fish, or any intermediate entities that could link them. Group these rules by the entities they affect."
    },
    {
      "label": "chain_tracer",
      "instructions": "Using the extracted rules, attempt to construct a logical path from the butterfly to the fish. Trace every possible sequence of rule triggers to see if the butterfly's actions can eventually result in the fish receiving a secret."
    },
    {
      "label": "logic_verifier",
      "instructions": "Evaluate the completed chain from the tracer. Determine if the chain is complete, if there are missing links, or if the rules are insufficient to guarantee the outcome. Specifically, check if the information flow is definitive or if the rules allow for the outcome to be unknown."
    }
  ],
  "synthesis_brief": "Combine the extracted rules and the traced paths to determine if a complete, deterministic chain exists. If the rules do not provide a direct or indirect causal link that guarantees the outcome, or if the chain is broken, conclude that the answer is unknown."
}

